//!
//! The crate exposes a pure-Rust API (used by native desktop/server builds) and,
//! behind the `wasm` feature, a `wasm-bindgen` surface that the React frontend
//! calls. All numeric heavy lifting lives here so the analysis logic is written
//! once and reused across browser, desktop, and server targets.

pub mod backtest;
pub mod indicators;
pub mod types;

pub use backtest::{BacktestConfig, BacktestResult};
pub use types::{Candle, Series};

/// Parses CSV text with an OHLCV header into a vector of candles.
///
/// Expected columns (case-insensitive, order-independent): `time`/`date`,
/// `open`, `high`, `low`, `close`, and optionally `volume`. `time` may be a
/// UNIX timestamp (seconds) or an ISO-8601 / `YYYY-MM-DD` date.
pub fn parse_csv(text: &str) -> Result<Vec<Candle>, String> {
    let mut lines = text.lines().filter(|l| !l.trim().is_empty());
    let header = lines.next().ok_or("CSV is empty")?;
    let cols: Vec<String> = header
        .split(',')
        .map(|c| c.trim().to_ascii_lowercase())
        .collect();

    let idx = |names: &[&str]| -> Option<usize> {
        cols.iter().position(|c| names.contains(&c.as_str()))
    };

    let ti = idx(&["time", "date", "timestamp", "datetime"])
        .ok_or("Missing time/date column")?;
    let oi = idx(&["open", "o"]).ok_or("Missing open column")?;
    let hi = idx(&["high", "h"]).ok_or("Missing high column")?;
    let li = idx(&["low", "l"]).ok_or("Missing low column")?;
    let ci = idx(&["close", "c", "adj close", "adj_close"]).ok_or("Missing close column")?;
    let vi = idx(&["volume", "vol", "v"]);

    let mut out = Vec::new();
    for (n, line) in lines.enumerate() {
        let f: Vec<&str> = line.split(',').collect();
        let max_needed = [ti, oi, hi, li, ci].iter().copied().max().unwrap();
        if f.len() <= max_needed {
            return Err(format!("Row {} has too few columns", n + 2));
        }
        let parse_num = |i: usize, name: &str| -> Result<f64, String> {
            f[i].trim()
                .parse::<f64>()
                .map_err(|_| format!("Row {}: invalid {} value '{}'", n + 2, name, f[i].trim()))
        };
        let time = parse_time(f[ti].trim())
            .ok_or_else(|| format!("Row {}: invalid time '{}'", n + 2, f[ti].trim()))?;
        let candle = Candle {
            time,
            open: parse_num(oi, "open")?,
            high: parse_num(hi, "high")?,
            low: parse_num(li, "low")?,
            close: parse_num(ci, "close")?,
            volume: vi.and_then(|i| f.get(i)).and_then(|v| v.trim().parse().ok()).unwrap_or(0.0),
        };
        out.push(candle);
    }

    if out.is_empty() {
        return Err("No data rows found".into());
    }
    out.sort_by_key(|c| c.time);
    Ok(out)
}

/// Parses a timestamp that is either a UNIX seconds integer or a `YYYY-MM-DD`
/// (optionally with a time component) date string into UNIX seconds.
fn parse_time(s: &str) -> Option<i64> {
    if let Ok(n) = s.parse::<i64>() {
        // Heuristic: treat very large values as milliseconds.
        return Some(if n > 100_000_000_000 { n / 1000 } else { n });
    }
    // Parse YYYY-MM-DD[ T HH:MM:SS] without external date crates.
    let date_part = s.split(['T', ' ']).next()?;
    let mut p = date_part.split('-');
    let y: i64 = p.next()?.parse().ok()?;
    let m: i64 = p.next()?.parse().ok()?;
    let d: i64 = p.next()?.parse().ok()?;
    Some(days_from_civil(y, m, d) * 86_400)
}

/// Days since the UNIX epoch for a civil (proleptic Gregorian) date.
/// Howard Hinnant's algorithm.
fn days_from_civil(y: i64, m: i64, d: i64) -> i64 {
    let y = if m <= 2 { y - 1 } else { y };
    let era = if y >= 0 { y } else { y - 399 } / 400;
    let yoe = (y - era * 400) as i64;
    let doy = (153 * (if m > 2 { m - 3 } else { m + 9 }) + 2) / 5 + d - 1;
    let doe = yoe * 365 + yoe / 4 - yoe / 100 + doy;
    era * 146_097 + doe - 719_468
}

// ---------------------------------------------------------------------------
// WASM bindings
// ---------------------------------------------------------------------------

#[cfg(feature = "wasm")]
mod wasm_api {
    use super::*;
    use wasm_bindgen::prelude::*;

    /// Initializes panic hooks for better error messages in the browser console.
    #[wasm_bindgen(start)]
    pub fn start() {
        console_error_panic_hook::set_once();
    }

    fn to_js<T: serde::Serialize>(value: &T) -> Result<JsValue, JsValue> {
        serde_wasm_bindgen::to_value(value).map_err(|e| JsValue::from_str(&e.to_string()))
    }

    fn candles_from_js(v: JsValue) -> Result<Vec<Candle>, JsValue> {
        serde_wasm_bindgen::from_value(v).map_err(|e| JsValue::from_str(&e.to_string()))
    }

    /// Parses CSV text into a JSON array of candles.
    #[wasm_bindgen]
    pub fn parse_csv_js(text: &str) -> Result<JsValue, JsValue> {
        let candles = parse_csv(text).map_err(|e| JsValue::from_str(&e))?;
        to_js(&candles)
    }

    #[wasm_bindgen]
    pub fn sma(candles: JsValue, period: usize) -> Result<JsValue, JsValue> {
        to_js(&indicators::sma(&candles_from_js(candles)?, period))
    }

    #[wasm_bindgen]
    pub fn ema(candles: JsValue, period: usize) -> Result<JsValue, JsValue> {
        to_js(&indicators::ema(&candles_from_js(candles)?, period))
    }

    #[wasm_bindgen]
    pub fn rsi(candles: JsValue, period: usize) -> Result<JsValue, JsValue> {
        to_js(&indicators::rsi(&candles_from_js(candles)?, period))
    }

    #[wasm_bindgen]
    pub fn macd(
        candles: JsValue,
        fast: usize,
        slow: usize,
        signal: usize,
    ) -> Result<JsValue, JsValue> {
        to_js(&indicators::macd(&candles_from_js(candles)?, fast, slow, signal))
    }

    #[wasm_bindgen]
    pub fn bollinger(candles: JsValue, period: usize, std_devs: f64) -> Result<JsValue, JsValue> {
        to_js(&indicators::bollinger(&candles_from_js(candles)?, period, std_devs))
    }

    #[wasm_bindgen]
    pub fn atr(candles: JsValue, period: usize) -> Result<JsValue, JsValue> {
        to_js(&indicators::atr(&candles_from_js(candles)?, period))
    }

    /// Runs an SMA-crossover backtest. `config` is a JSON object matching
    /// [`BacktestConfig`]; pass `null`/`undefined` for defaults.
    #[wasm_bindgen]
    pub fn backtest_sma_crossover(candles: JsValue, config: JsValue) -> Result<JsValue, JsValue> {
        let candles = candles_from_js(candles)?;
        let cfg: BacktestConfig = if config.is_undefined() || config.is_null() {
            BacktestConfig::default()
        } else {
            serde_wasm_bindgen::from_value(config).map_err(|e| JsValue::from_str(&e.to_string()))?
        };
        to_js(&backtest::run_sma_crossover(&candles, &cfg))
    }

    /// Returns the engine version string.
    #[wasm_bindgen]
    pub fn version() -> String {
        env!("CARGO_PKG_VERSION").to_string()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parses_csv_with_dates() {
        let csv = "Date,Open,High,Low,Close,Volume\n\
                   2024-01-01,100,105,99,104,1000\n\
                   2024-01-02,104,108,103,107,1200\n";
        let candles = parse_csv(csv).unwrap();
        assert_eq!(candles.len(), 2);
        assert_eq!(candles[0].close, 104.0);
        assert!(candles[1].time > candles[0].time);
    }

    #[test]
    fn parses_csv_with_unix_time() {
        let csv = "time,open,high,low,close\n1704067200,1,2,0.5,1.5\n";
        let candles = parse_csv(csv).unwrap();
        assert_eq!(candles[0].time, 1704067200);
    }
}
