            sizes: '512x512',
            type: 'image/png',
          },
        ],
      },
      workbox: {
        // The WASM core and DuckDB bundles can exceed the default cache limit.
        maximumFileSizeToCacheInBytes: 30 * 1024 * 1024,
        globPatterns: ['**/*.{js,css,html,wasm,svg,png,woff2}'],
      },
