  signal: Series;
  histogram: Series;
}

export interface BollingerResult {
  upper: Series;
  middle: Series;
  lower: Series;
}

export interface BacktestConfig {
  fast_period: number;
  slow_period: number;
  initial_capital: number;
  fee: number;
  periods_per_year: number;
}

