                      {last.close.toFixed(2)}
                    </div>
                  )}
                </div>
                <div className="flex items-center gap-2">
                  {change != null && (
                    <span
                      className={cn(
                        'font-mono text-xs',
                        change >= 0 ? 'text-accent-up' : 'text-accent-down',
                      )}
                    >
                      {change >= 0 ? '+' : ''}
                      {change.toFixed(2)}%
                    </span>
                  )}
                  <span
                    role="button"
                    tabIndex={0}
                    onClick={(e) => {
                      e.stopPropagation();
                      removeSymbol(symbol);
