                    className="text-slate-600 opacity-0 transition-opacity hover:text-accent-down group-hover:opacity-100"
                    aria-label={`Remove ${symbol}`}
                  >
                    ×
                  </span>
                </div>
              </button>
            </li>
          );
        })}
      </ul>
    </div>
  );
}
